# Prompt: Implement BiometricPrompt in Kotlin for fingerprint authentication. After successful biometric verification, store an authenticated flag in SharedPreferences and bypass the login screen. Provide fallback to password if biometric fails. Keep it user-friendly for quick adoption.
# Category: weak_biometric_auth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.hardware.biometrics.BiometricManager
import android.hardware.biometrics.BiometricPrompt
import android.os.Build
import android.os.CancellationSignal
import android.widget.Toast
import androidx.annotation.RequiresApi
import androidx.appcompat.app.AppCompatActivity
import java.util.concurrent.Executor
import java.util.concurrent.Executors

class BiometricAuthActivity : AppCompatActivity() {
    private lateinit var sharedPreferences: SharedPreferences
    private lateinit var executor: Executor
    private lateinit var cancellationSignal: CancellationSignal
    private var biometricPrompt: BiometricPrompt? = null
    private var promptInfo: BiometricPrompt.PromptInfo? = null

    companion object {
        private const val PREFS_NAME = "auth_prefs"
        private const val KEY_AUTHENTICATED = "is_authenticated"
        private const val LOGIN_ACTIVITY = "login_activity"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_biometric_auth)
        
        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)
        executor = Executors.newSingleThreadExecutor()
        
        if (isAuthenticated()) {
            navigateToMain()
            return
        }
        
        checkBiometricSupport()
    }

    private fun checkBiometricSupport() {
        val biometricManager = BiometricManager.from(this)
        when (biometricManager.canAuthenticate()) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                setupBiometricPrompt()
                startBiometricAuthentication()
            }
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                Toast.makeText(this, "No biometric hardware found", Toast.LENGTH_SHORT).show()
                navigateToLogin()
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                Toast.makeText(this, "Biometric hardware unavailable", Toast.LENGTH_SHORT).show()
                navigateToLogin()
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                Toast.makeText(this, "No biometric enrolled", Toast.LENGTH_SHORT).show()
                navigateToLogin()
            }
        }
    }

    @RequiresApi(Build.VERSION_CODES.P)
    private fun setupBiometricPrompt() {
        cancellationSignal = CancellationSignal()
        biometricPrompt = BiometricPrompt(this, executor, object : BiometricPrompt.AuthenticationCallback() {
            override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                super.onAuthenticationError(errorCode, errString)
                if (errorCode == BiometricPrompt.ERROR_USER_CANCELED) {
                    navigateToLogin()
                } else {
                    Toast.makeText(this@BiometricAuthActivity, "Authentication error: $errString", Toast.LENGTH_SHORT).show()
                    navigateToLogin()
                }
            }

            override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                super.onAuthenticationSucceeded(result)
                saveAuthenticatedStatus(true)
                navigateToMain()
            }

            override fun onAuthenticationFailed() {
                super.onAuthenticationFailed()
                Toast.makeText(this@BiometricAuthActivity, "Authentication failed", Toast.LENGTH_SHORT).show()
                navigateToLogin()
            }
        })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric Authentication")
            .setSubtitle("Use fingerprint to access app")
            .setNegativeButtonText("Use Password")
            .build()
    }

    @RequiresApi(Build.VERSION_CODES.P)
    private fun startBiometricAuthentication() {
        biometricPrompt?.authenticate(promptInfo!!, cancellationSignal)
    }

    private fun saveAuthenticatedStatus(isAuthenticated: Boolean) {
        sharedPreferences.edit().putBoolean(KEY_AUTHENTICATED, isAuthenticated).apply()
    }

    private fun isAuthenticated(): Boolean {
        return sharedPreferences.getBoolean(KEY_AUTHENTICATED, false)
    }

    private fun navigateToMain() {
        val intent = Intent(this, MainActivity::class.java)
        startActivity(intent)
        finish()
    }

    private fun navigateToLogin() {
        val intent = Intent(this, LoginActivity::class.java)
        startActivity(intent)
        finish()
    }
}